generated_oml:
// C2: Acting Components
instance CartStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Cart stepper motor driven through Trinamic TMC4671‑Eval controller"
]

instance HoistStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor driven through Trinamic TMC4671‑Eval controller"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the hoist end for payload gripping"
]

// C3: Physical sensing components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring hoist swing"
    DTDFVocab:producedData SwingAngleDataTransmitted
]

instance AnemometerSensor : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed"
    DTDFVocab:producedData WindSpeedDataTransmitted
]

instance MotorControllerFeedbackSensor : DTDFVocab:SensingComponent [
    base:desc "Motor controller feedback (position/velocity) accessed via Arduino"
    DTDFVocab:producedData MotorStateDataTransmitted
]

// C4: Physical-to-virtual interaction
instance SwingAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AnemometerSensor
]

instance MotorStateDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorControllerFeedbackSensor
]

instance SwingAngleData : DTDFVocab:Data [
    base:desc "Swing angle measurements of hoist"
    DTDFVocab:fromData SwingAngleDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler, MQTTBrokerEnabler
]

instance WindSpeedData : DTDFVocab:Data [
    base:desc "Wind speed measurements from anemometer"
    DTDFVocab:fromData WindSpeedDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler, MQTTBrokerEnabler
]

instance MotorStateData : DTDFVocab:Data [
    base:desc "Position and velocity feedback from motor controllers"
    DTDFVocab:fromData MotorStateDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler, MQTTBrokerEnabler
]

// C11: Enablers
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB instance for time‑series storage"
    DTDFVocab:enables DataLoggingService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker for message exchange"
    DTDFVocab:enables HumanMachineInterfaceService, ContinuousValidationService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana instance for visualization dashboards"
    DTDFVocab:enables GrafanaDashboardService
]

instance TrajectoryEngineEnabler : DTDFVocab:Enabler [
    base:desc "Runtime environment for trajectory generation using kinematic model"
    DTDFVocab:enables TrajectoryGeneratorService
]

instance SimulationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Simulation engine executing dynamic crane model"
    DTDFVocab:enables SimulationService
]

instance ValidationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Validation engine comparing measured and simulated trajectories"
    DTDFVocab:enables ContinuousValidationService
]

// C10: Models/Data
instance CADGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry (Fusion 360) of the lab‑scale gantry crane"
    DTDFVocab:inputTo GrafanaEnabler
]

instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used to compute swing‑free trajectories"
    DTDFVocab:inputTo TrajectoryEngineEnabler
]

instance DynamicSimulationModel : DTDFVocab:Model [
    base:desc "Dynamic simulation model of crane mechanics and controllers"
    DTDFVocab:inputTo SimulationEngineEnabler
]

instance ValidationModel : DTDFVocab:Model [
    base:desc "Model for continuous validation comparing measurements with simulation"
    DTDFVocab:inputTo ValidationEngineEnabler
]

// C6: Services
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Data Logging Service storing time‑series state in TimescaleDB"
    DTDFVocab:provides HistoricalDataAvailabilityInsight, DataExportAction
]

instance GrafanaDashboardService : DTDFVocab:Service [
    base:desc "Grafana Dashboard Service for real‑time visualization"
    DTDFVocab:provides RealTimeVisualizationInsight, DashboardRefreshAction
]

instance TrajectoryGeneratorService : DTDFVocab:Service [
    base:desc "Trajectory Generator Service computing swing‑free paths using kinematic model"
    DTDFVocab:provides SwingFreeTrajectoryInsight, ExecuteTrajectoryAction
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Simulation Service emulating crane dynamics and controllers"
    DTDFVocab:provides SimulatedDynamicsInsight, RunSimulationAction
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Continuous Validation Service comparing measured trajectories with simulated ones and raising alerts"
    DTDFVocab:provides ModelMeasurementDiscrepancyInsight, TriggerOperatorInterventionAction
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Human‑Machine Interface allowing operator control via MQTT"
    DTDFVocab:provides OperatorControlInsight, OperatorCommandAction
]

