// Additional Physical Components
instance MetalFrameComponent : DTDFVocab:Component [
    base:desc "Metal frame of the lab‑scale gantry crane"
]

instance PowerSupplyUnitComponent : DTDFVocab:Component [
    base:desc "Power supply unit providing voltage to motors and electronics"
]

instance ArduinoControlBoardComponent : DTDFVocab:Component [
    base:desc "Arduino‑based measurement & control board interfacing sensors and actuators"
]

// Environment
instance LaboratoryGantryCraneEnvironment : DTDFVocab:Environment [
    base:contains MetalFrameComponent, PowerSupplyUnitComponent, ArduinoControlBoardComponent,
                CartStepperMotorActuator, HoistStepperMotorActuator, ElectromagnetActuator,
                SwingAngleEncoder, AnemometerSensor, MotorControllerFeedbackSensor
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The Trajectory Generator Service publishes optimal motion set‑points via MQTT; the Control Application subscribes to these messages and, through the Physical Crane Interface, sends command values to the motor controllers and electromagnet, thereby moving the crane in real time."
]

