instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin spans design (CAD models of the crane in Autodesk Fusion 360), manufacturing (Bill‑of‑Materials and hardware assembly), and operation (real‑time logging, simulation, validation, and trajectory optimisation) phases."
]

