    base:desc "Continuous Validation Service calculates distance metrics between measured trajectories and simulated counterparts, compares them against configurable thresholds, and notifies operators when deviations exceed the limits, thereby providing on‑line fidelity assessment of the kinematic and dynamic models."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between PT and DT uses TCP/IP‑based MQTT (Eclipse Mosquitto) for command and status messages, and PostgreSQL‑compatible SQL over TCP/IP for time‑series data access to TimescaleDB; the Python interface runs on the same host PC as the crane controller."
